const body = $('Webhook').first().json.body || {};
const items = Array.isArray(body.items) ? body.items : [];
return items.map((it) => ({ json: {
  url: it.url || null,
  rawText: it.rawText || null,
  title: it.title || null,
  doi: it.doi || null,
  arxivId: it.arxivId || null,
  isbn: it.isbn || null,
  chapterTitle: it.chapterTitle || null,
  pages: it.pages || null,
  sourceType: it.sourceType || 'rss',
  category_hint: it.category_hint || null,
  publishedAt: it.publishedAt || null,
}}));

const SYSTEM_GEN = "Eres un extractor de resumenes para un feed de conocimiento.\nRecibes el texto de un contenido y devuelves UNICAMENTE un objeto JSON valido, sin texto antes ni despues, sin bloques de codigo, sin explicaciones.\n\nEsquema exacto:\n{\n  \"title\": string,        // titulo claro, max 80 caracteres\n  \"summary\": string,      // 3 a 5 frases, en espanol, autocontenido, sin meta-referencias\n  \"category\": string,     // EXACTAMENTE uno de: \"ciencia\" | \"filosofia\" | \"tecnologia\" | \"web\" | \"podcast\"\n  \"estReadMin\": number    // minutos de lectura del ORIGINAL, entero 1-30\n}\n\nReglas:\n- El summary debe poder leerse solo, como una tarjeta, sin abrir el original.\n- Si no puedes determinar la categoria, usa \"web\".\n- No inventes datos que no esten en el texto.\n- NO generes ni inventes citas, autores, anios ni DOIs. Eso se maneja por otro camino.\n- Responde solo con el JSON.";
const SYSTEM_SCI = "Eres un extractor de resumenes para un feed de conocimiento, especializado en articulos cientificos. Recibes el texto (o abstract) de un paper y devuelves UNICAMENTE un objeto JSON valido, sin texto antes ni despues, sin bloques de codigo.\n\nEsquema exacto:\n{\n  \"title\": string,        // titulo claro y conciso, max 80 caracteres\n  \"summary\": string,      // 3 a 5 frases en espanol. Prioriza EL HALLAZGO o la\n                          // contribucion: que encontraron y por que importa.\n                          // Evita 'el articulo habla de'.\n  \"category\": string,     // normalmente \"ciencia\"; usa \"tecnologia\" o \"filosofia\" si aplica\n  \"estReadMin\": number    // minutos de lectura estimados, entero 1-30\n}\n\nReglas:\n- El summary debe poder leerse solo, sin abrir el paper.\n- No inventes resultados, cifras ni conclusiones que no esten en el texto.\n- NO generes ni inventes la cita, autores, anio ni DOI. Eso se construye aparte.\n- Responde solo con el JSON.";

function stripTags(s){
  return String(s||'')
    .replace(/<script[\s\S]*?<\/script>/gi,' ')
    .replace(/<style[\s\S]*?<\/style>/gi,' ')
    .replace(/<[^>]+>/g,' ')
    .replace(/&[a-z]+;/gi,' ')
    .replace(/\s+/g,' ').trim();
}
function apaNameFromFull(n){
  const parts = String(n||'').trim().split(/\s+/).filter(Boolean);
  if(parts.length===0) return '';
  const fam = parts.pop();
  const gi = parts.map(p=>p[0].toUpperCase()+'.').join(' ');
  return fam + (gi ? ', ' + gi : '');
}
function joinAuthors(arr){
  const a = (arr||[]).filter(Boolean);
  if(a.length===0) return '';
  if(a.length===1) return a[0];
  if(a.length<=20) return a.slice(0,-1).join(', ') + ', & ' + a[a.length-1];
  return a.slice(0,19).join(', ') + ', ... ' + a[a.length-1];
}
function apaCrossref(m){
  m = m || {};
  const authors = joinAuthors((m.author||[]).map(p=>{
    const fam = p.family || '';
    const gi = String(p.given||'').trim().split(/\s+/).filter(Boolean).map(x=>x[0].toUpperCase()+'.').join(' ');
    return fam ? (fam + (gi ? ', ' + gi : '')) : (p.name || '');
  }));
  let year='';
  try { year = (m.issued && m.issued['date-parts'] && m.issued['date-parts'][0] && m.issued['date-parts'][0][0]) ||
               (m.published && m.published['date-parts'] && m.published['date-parts'][0] && m.published['date-parts'][0][0]) || ''; } catch(e){}
  const title = (m.title && m.title[0]) || '';
  const journal = (m['container-title'] && m['container-title'][0]) || '';
  const vol = m.volume || '';
  const iss = m.issue ? '(' + m.issue + ')' : '';
  const pages = m.page || '';
  const doi = m.DOI ? 'https://doi.org/' + m.DOI : '';
  let s = (authors ? authors + ' ' : '') + '(' + (year || 's.f.') + '). ' + title + '. ';
  if(journal){ s += journal; if(vol) s += ', ' + vol + iss; if(pages) s += ', ' + pages; s += '. '; }
  if(doi) s += doi;
  return s.trim();
}
function parseArxiv(xml){
  xml = String(xml||'');
  const entry = xml.split('<entry>')[1] || xml;
  const get = (tag) => { const m = entry.match(new RegExp('<'+tag+'>([\\s\\S]*?)<\\/'+tag+'>')); return m ? m[1].trim() : ''; };
  const names = [];
  const re = /<author>[\s\S]*?<name>([\s\S]*?)<\/name>[\s\S]*?<\/author>/g;
  let mm; while((mm = re.exec(entry)) !== null){ names.push(mm[1].trim()); }
  return { title: get('title').replace(/\s+/g,' ').trim(), summary: get('summary').replace(/\s+/g,' ').trim(), published: get('published'), names };
}
function apaArxiv(meta, id){
  const authors = joinAuthors((meta.names||[]).map(apaNameFromFull));
  const year = (meta.published||'').slice(0,4) || 's.f.';
  return (authors ? authors + ' ' : '') + '(' + year + '). ' + meta.title + ' [Preprint]. arXiv. https://arxiv.org/abs/' + id;
}
function apaBook(vol, it){
  const info = (vol && vol.items && vol.items[0] && vol.items[0].volumeInfo) || {};
  const authors = joinAuthors((info.authors||[]).map(apaNameFromFull));
  const year = (info.publishedDate||'').slice(0,4) || 's.f.';
  const title = info.title || (it.title || '');
  const publisher = info.publisher || '';
  let s = (authors ? authors + ' ' : '') + '(' + year + '). ' + title + '. ' + (publisher ? publisher + '.' : '');
  const extra = [];
  if(it.chapterTitle) extra.push('Cap.: ' + it.chapterTitle);
  if(it.pages) extra.push('pp. ' + it.pages);
  if(extra.length) s += ' [' + extra.join(', ') + ']';
  return s.trim();
}

const cfg = $('Config').first().json;
const maxChars = cfg.maxChars || 6000;
const out = [];

for (const item of $input.all()) {
  const it = item.json;
  let text = '';
  let citation = null;
  let citationSource = null;
  let originalUrl = it.url || null;
  let publishedAt = it.publishedAt || null;
  let err = null;

  // --- 1. Metadatos -> cita APA (determinista, no LLM) ---
  try {
    if (it.doi) {
      const r = await this.helpers.httpRequest({ method:'GET', json:true, timeout:15000,
        url:'https://api.crossref.org/works/' + encodeURIComponent(it.doi),
        headers:{'User-Agent':'FeedConocimiento/1.0 (mailto:hola@juliangomez.me)'} });
      citation = apaCrossref(r.message); citationSource = 'crossref';
      originalUrl = originalUrl || ('https://doi.org/' + it.doi);
      if (!it.rawText && !it.url && r.message && r.message.abstract) text = stripTags(r.message.abstract);
    } else if (it.arxivId) {
      const xml = await this.helpers.httpRequest({ method:'GET', timeout:15000,
        url:'http://export.arxiv.org/api/query?id_list=' + encodeURIComponent(it.arxivId) });
      const meta = parseArxiv(xml);
      citation = apaArxiv(meta, it.arxivId); citationSource = 'arxiv';
      originalUrl = originalUrl || ('https://arxiv.org/abs/' + it.arxivId);
      if (!it.rawText && meta.summary) text = meta.summary;
      if (!publishedAt && meta.published) { const d = new Date(meta.published); if (!isNaN(d.getTime())) publishedAt = d.toISOString(); }
    } else if (it.isbn) {
      const vol = await this.helpers.httpRequest({ method:'GET', json:true, timeout:15000,
        url:'https://www.googleapis.com/books/v1/volumes?q=isbn:' + encodeURIComponent(it.isbn) });
      citation = apaBook(vol, it); citationSource = 'isbn';
    }
  } catch (e) { /* la cita es opcional: si falla, queda null */ }

  // --- 2. Texto del contenido ---
  if (!text) {
    if (it.rawText) {
      text = stripTags(it.rawText);
    } else if (it.url) {
      try {
        const bodyResp = await this.helpers.httpRequest({ method:'GET', timeout:20000,
          url: it.url, headers:{'User-Agent':'Mozilla/5.0 (compatible; FeedConocimientoBot/1.0)'} });
        text = stripTags(bodyResp);
      } catch (e) { err = 'fetch_failed'; }
    } else {
      err = 'no_content';
    }
  }

  text = String(text).slice(0, maxChars);
  if (!err && text.length < 120) err = 'too_short';

  const isSci = (it.sourceType === 'scientific');
  const system = isSci ? SYSTEM_SCI : SYSTEM_GEN;
  const userMsg = 'Categoria sugerida: ' + (it.category_hint || 'ninguna') + '\n\nTexto:\n\n' + text;
  const llmBody = { model: cfg.llmModel, messages: [
    { role:'system', content: system },
    { role:'user', content: userMsg },
  ], temperature: 0.2, stream: false };

  out.push({ json: {
    originalUrl,
    sourceType: it.sourceType || 'rss',
    category_hint: it.category_hint || null,
    title: it.title || null,
    publishedAt,
    citation,
    citationSource,
    text,
    _error: err,
    _llmBody: llmBody,
  }});
}

return out;

const preps = $('Prepare').all();
const responses = $input.all();
const out = { ok: true, cards: [], failed: [] };
const allowed = ['ciencia', 'filosofia', 'tecnologia', 'web', 'podcast'];

for (let i = 0; i < responses.length; i++) {
  const p = (preps[i] && preps[i].json) || {};
  const url = p.originalUrl || 'unknown';

  if (p._error) { out.failed.push({ url, error: p._error }); continue; }

  const r = (responses[i] && responses[i].json) || {};
  if (r.error) { out.failed.push({ url, error: 'llm_failed' }); continue; }

  let content = '';
  if (r.choices && r.choices[0] && r.choices[0].message) content = r.choices[0].message.content || '';
  else if (r.message && r.message.content) content = r.message.content;
  else if (typeof r.response === 'string') content = r.response;

  const m = String(content).match(/\{[\s\S]*\}/);
  if (!m) { out.failed.push({ url, error: 'no_json' }); continue; }

  try {
    const card = JSON.parse(m[0]);
    if (!card.summary) { out.failed.push({ url, error: 'incomplete' }); continue; }
    let title = card.title;
    if ((p.sourceType === 'book' || p.sourceType === 'manual') && p.title) title = p.title;
    if (!title) { out.failed.push({ url, error: 'incomplete' }); continue; }
    const fallbackCat = (p.sourceType === 'scientific') ? 'ciencia' : 'web';
    out.cards.push({
      title: String(title).slice(0, 120),
      summary: card.summary,
      category: allowed.includes(card.category) ? card.category : fallbackCat,
      estReadMin: Number.isFinite(card.estReadMin) ? Math.min(30, Math.max(1, Math.round(card.estReadMin))) : 2,
      originalUrl: p.originalUrl || null,
      citation: p.citation || null,
      citationSource: p.citationSource || null,
      sourceType: p.sourceType || 'rss',
      publishedAt: p.publishedAt || null,
    });
  } catch (e) {
    out.failed.push({ url, error: 'json_parse' });
  }
}

return [{ json: out }];
